import{_ as o,c as i,o as t,a1 as a}from"./chunks/framework.DDNAyvCW.js";const n="/assets/mobile_ai.4NNpzKtS.jpg",l="/assets/mobile_ai_chat.C4Fs1OrI.jpg",s="/assets/mobile_ai_term.BVa0d1wW.jpg",f=JSON.parse('{"title":"AI Dialog","description":"","frontmatter":{},"headers":[],"relativePath":"docs/mobile/ai-agent/index.md","filePath":"docs/mobile/ai-agent/index.md"}'),r={name:"docs/mobile/ai-agent/index.md"};function d(c,e,m,p,u,h){return t(),i("div",null,e[0]||(e[0]=[a('<h1 id="ai-dialog" tabindex="-1">AI Dialog <a class="header-anchor" href="#ai-dialog" aria-label="Permalink to &quot;AI Dialog&quot;">​</a></h1><p>AI Dialog on mobile helps you execute commands, troubleshoot issues, and ask day-to-day operations questions from your phone.</p><p>The mobile experience currently focuses on two modes: <code>Chat</code> and <code>Term</code>. You can switch between them from the mode selector below the input box.</p><p><img src="'+n+'" alt=""></p><h2 id="chat-mode" tabindex="-1">Chat Mode <a class="header-anchor" href="#chat-mode" aria-label="Permalink to &quot;Chat Mode&quot;">​</a></h2><p><code>Chat</code> mode is designed for working with AI on analysis, explanations, and command suggestions.</p><p>Usage notes:</p><ul><li>Sign in before using it</li><li>Select an available model in Profile first</li><li>Supports text input</li><li>Supports voice input</li><li>AI can understand natural language and generate executable commands</li><li>AI can continue troubleshooting based on the current context</li></ul><p>Best for:</p><ul><li>Learning Linux commands</li><li>Getting troubleshooting suggestions</li><li>Asking for script-writing help</li><li>Understanding configuration files</li><li>Reviewing operations best practices</li></ul><p><img src="'+l+'" alt=""></p><h2 id="term-mode" tabindex="-1">Term Mode <a class="header-anchor" href="#term-mode" aria-label="Permalink to &quot;Term Mode&quot;">​</a></h2><p><code>Term</code> mode directly executes commands without sending them through AI.</p><p>Usage notes:</p><ul><li>Connect to a server first</li><li>If no server is connected, the page shows an entry to connect a host</li><li>Supports text input</li><li>Supports voice input</li><li>Returns the command output directly</li></ul><p>Best for:</p><ul><li>Running a quick one-off command</li><li>Checking host status fast</li></ul><p><img src="'+s+'" alt=""></p><h2 id="typical-workflow" tabindex="-1">Typical Workflow <a class="header-anchor" href="#typical-workflow" aria-label="Permalink to &quot;Typical Workflow&quot;">​</a></h2><ol><li>Open the AI dialog page</li><li>Connect to the target host</li><li>Choose <code>Chat</code> or <code>Term</code></li><li>Enter a question or command, or start a request with voice input</li><li>Review the result and continue if needed</li></ol><h2 id="recommendations" tabindex="-1">Recommendations <a class="header-anchor" href="#recommendations" aria-label="Permalink to &quot;Recommendations&quot;">​</a></h2><ul><li>Use <code>Chat</code> mode first when you need explanation, planning, or troubleshooting</li><li>After signing in, confirm your model settings in Profile before entering <code>Chat</code> mode</li></ul>',22)]))}const _=o(r,[["render",d]]);export{f as __pageData,_ as default};
